                                add(grid);

                                var chart = new AGBarChart();
                                chart.getData().addSeries("revenue");
                                add(chart);
                            }
                        }""");
        beforeSlot.addAttribute("slot", "before");
        comparison.add(beforeSlot);

        var afterSlot = codeBlockWithTitle("Generated Angular Component",
                """
                        <sales-dashboard>
                          <ag-grid-angular
                            [gridOptions]="gridOptions"
                            [columnDefs]="columnDefs"
                            [rowData]="rowData">
                          </ag-grid-angular>

                          <ag-charts
                            [options]="chartOptions">
                          </ag-charts>
                        </sales-dashboard>""", PrismLanguage.HTML);
        afterSlot.addAttribute("slot", "after");
        comparison.add(afterSlot);

        content.add(comparison);

        content.add(captionText("This generates an Angular component, a route at /dashboard, "
                + "and wires AG Grid + AG Charts — all from a single Java class."));

