        max-width: var(--line-length, none);
    }

    .line-length-xs {
        --line-length: var(--line-length-xs);
    }
    .line-length-s {
        --line-length: var(--line-length-s);
    }
    .line-length-m {
        --line-length: var(--line-length-m);
    }
    .line-length-l {
        --line-length: var(--line-length-l);
    }
    .line-length-xl {
        --line-length: var(--line-length-xl);
    }
    .line-length-none {
        --line-length: none;
    }
